_NuFrRa_async (c, a) => {
    var o = await a("php artisan list --format=json");
    let i = [];

    try {
      JSON.parse(o).commands.map(t => {
        i.push({
          name: t.name,
          description: t.description,
          icon: "https://web.tinkerwell.app/img/laravel.3cab6a56.png",
          args: Object.keys(t.definition.arguments).map(e => {
            let n = t.definition.arguments[e];
            return {
              name: n.name,
              description: n.description,
              isOptional: !n.is_required
            };
          }),
          options: Object.keys(t.definition.options).map(e => {
            let n = t.definition.options[e],
                s = [n.name];
            return n.shortcut !== "" && s.push(n.shortcut), {
              name: s,
              description: n.description
            };
          })
        });
      });
    } catch (r) {}

    return {
      name: "artisan",
      debounce: !0,
      subcommands: i
    };
  }
